<?php
declare(strict_types=1); namespace Vigilancia\Validation;
final class Validator{public static function required(array $data,array $fields):array{$errors=[];foreach($fields as $field)if(!isset($data[$field])||trim((string)$data[$field])==='')$errors[$field][]='Este campo es obligatorio.';return $errors;}public static function email(string $value):bool{return filter_var($value,FILTER_VALIDATE_EMAIL)!==false;}public static function strongPassword(string $value):bool{return strlen($value)>=12&&preg_match('/[A-Z]/',$value)&&preg_match('/[a-z]/',$value)&&preg_match('/\d/',$value)&&preg_match('/[^A-Za-z0-9]/',$value);}}
